#include<bits/stdc++.h>
using namespace std;
int n;
priority_queue<int,vector<int>,greater<int> > q;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int op;
        cin>>op;
        if(op==1)
        {
            int t;
            cin>>t;
            q.push(t);
        }
        else if(op==2) cout<<q.top()<<'\n';
        else q.pop();
    }
    return 0;
}
